module signal_generator (
    input clk,
    input rst_n,
    output reg [4:0] wave
);

localparam UP = 2'b00;
localparam DOWN = 2'b01;

reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        state <= UP;
        wave <= 5'd0;
    end else begin
        case(state)
            UP: begin
                if(wave == 5'd31) begin
                    state <= DOWN;
                end else begin
                    wave <= wave + 1;
                end
            end

            DOWN: begin
                if(wave == 5'd0) begin
                    state <= UP;
                end else begin
                    wave <= wave - 1;
                end
            end
        endcase
    end
end
endmodule
